```typescript
export type ChargeState =
  | { status: "none" }
  | { status: "authorized"; id: string; amount: number }
  | { status: "captured"; id: string; amount: number; capturedAt: string }
  | { status: "voided"; id: string };

export type ChargeCommand =
  | { type: "authorize"; id: string; amount: number }
  | { type: "capture"; at: string }
  | { type: "void"; reason: string };

export type ChargeEvent =
  | { type: "ChargeAuthorized"; id: string; amount: number }
  | { type: "ChargeCaptured"; at: string }
  | { type: "ChargeVoided"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const chargeDecider: Decider<ChargeCommand, ChargeEvent, ChargeState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "authorize":
        if (state.status !== "none") throw new DomainError("CHARGE_EXISTS");
        if (command.amount <= 0) throw new DomainError("INVALID_AMOUNT");
        return [{ type: "ChargeAuthorized", id: command.id, amount: command.amount }];
      case "capture":
        if (state.status === "voided") throw new DomainError("CHARGE_VOIDED");
        if (state.status !== "authorized") throw new DomainError("NOT_AUTHORIZED");
        return [{ type: "ChargeCaptured", at: command.at }];
      case "void":
        if (state.status === "captured") throw new DomainError("ALREADY_CAPTURED");
        if (state.status !== "authorized") throw new DomainError("NOT_AUTHORIZED");
        return [{ type: "ChargeVoided", reason: command.reason }];
      default: { const _n: never = command; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ChargeAuthorized":
        return { status: "authorized", id: event.id, amount: event.amount };
      case "ChargeCaptured":
        if (state.status !== "authorized") return state;
        return { status: "captured", id: state.id, amount: state.amount, capturedAt: event.at };
      case "ChargeVoided":
        if (state.status !== "authorized") return state;
        return { status: "voided", id: state.id };
      default: { const _n: never = event; return state; }
    }
  },
};
