```typescript
A Decider is a pure triple (initialState, decide, evolve). `decide` takes a command plus current state and returns events or throws a typed domain error. `evolve` folds events back into state. Because neither function does I/O, the aggregate is deterministic and easy to test.

```typescript
export type SettlementState =
  | { status: "none" }
  | { status: "open"; id: string; entries: number; total: number }
  | { status: "posted"; id: string; total: number }
  | { status: "closed"; id: string; total: number; closedAt: string };

export type SettlementCommand =
  | { type: "open"; id: string }
  | { type: "post"; amount: number }
  | { type: "close"; at: string };

export type SettlementEvent =
  | { type: "SettlementOpened"; id: string }
  | { type: "SettlementEntryPosted"; amount: number }
  | { type: "SettlementClosed"; at: string; total: number };

export class SettlementError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const settlementDecider: Decider<SettlementCommand, SettlementEvent, SettlementState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new SettlementError("ALREADY_OPEN");
        return [{ type: "SettlementOpened", id: command.id }];
      case "post":
        if (state.status !== "open") throw new SettlementError("NOT_OPEN");
        if (command.amount === 0) throw new SettlementError("ZERO_AMOUNT");
        return [{ type: "SettlementEntryPosted", amount: command.amount }];
      case "close":
        if (state.status !== "open") throw new SettlementError("NOT_OPEN");
        if (state.entries === 0) throw new SettlementError("NO_ENTRIES");
        return [{ type: "SettlementClosed", at: command.at, total: state.total }];
      default: { const _n: never = command; throw new SettlementError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SettlementOpened":
        return { status: "open", id: event.id, entries: 0, total: 0 };
      case "SettlementEntryPosted":
        if (state.status !== "open") return state;
        return { ...state, entries: state.entries + 1, total: state.total + event.amount };
      case "SettlementClosed":
        if (state.status !== "open") return state;
        return { status: "closed", id: state.id, total: event.total, closedAt: event.at };
      default: { const _n: never = event; return state; }
    }
  },
};
