export type PayoutState =
  | { status: "none" }
  | { status: "requested"; id: string; amount: number }
  | { status: "approved"; id: string; amount: number; approver: string }
  | { status: "executed"; id: string; amount: number; executedAt: string }
  | { status: "held"; id: string; reason: string };

export type PayoutCommand =
  | { type: "request"; id: string; amount: number }
  | { type: "approve"; approver: string }
  | { type: "execute"; at: string }
  | { type: "hold"; reason: string };

export type PayoutEvent =
  | { type: "PayoutRequested"; id: string; amount: number }
  | { type: "PayoutApproved"; approver: string }
  | { type: "PayoutExecuted"; at: string }
  | { type: "PayoutHeld"; reason: string };

export class PayoutError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "PayoutError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const payoutDecider: Decider<PayoutCommand, PayoutEvent, PayoutState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "request":
        if (state.status !== "none") throw new PayoutError("EXISTS");
        if (command.amount <= 0) throw new PayoutError("INVALID_AMOUNT");
        return [{ type: "PayoutRequested", id: command.id, amount: command.amount }];
      case "approve":
        if (state.status !== "requested") throw new PayoutError("NOT_REQUESTED");
        return [{ type: "PayoutApproved", approver: command.approver }];
      case "execute":
        if (state.status !== "approved") throw new PayoutError("NOT_APPROVED");
        return [{ type: "PayoutExecuted", at: command.at }];
      case "hold":
        if (state.status === "executed") throw new PayoutError("ALREADY_EXECUTED");
        if (state.status === "none") throw new PayoutError("NOT_FOUND");
        return [{ type: "PayoutHeld", reason: command.reason }];
      default: { const _n: never = command; throw new PayoutError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PayoutRequested":
        return { status: "requested", id: event.id, amount: event.amount };
      case "PayoutApproved":
        if (state.status !== "requested") return state;
        return { status: "approved", id: state.id, amount: state.amount, approver: event.approver };
      case "PayoutExecuted":
        if (state.status !== "approved") return state;
        return { status: "executed", id: state.id, amount: state.amount, executedAt: event.at };
      case "PayoutHeld":
        if (state.status === "none" || state.status === "executed") return state;
        return { status: "held", id: "id" in state ? state.id : "", reason: event.reason };
      default: { const _n: never = event; return state; }
    }
  },
};
