  switch (event.type) {
    case "SettlementEntryPosted": {
      const prior = view.totalsByDay[event.day] ?? 0;
      return { ...view, totalsByDay: { ...view.totalsByDay, [event.day]: prior + event.amount } };
    }
    case "SettlementClosed":
      return { ...view, closedIds: [...view.closedIds, event.id] };
    case "SettlementOpened":
      return view;
    default: { const _n: never = event; return view; }
  }
}

export function aggregateStream<V, E>(events: E[], reducer: (v: V, e: E) => V, initial: V): V {
  return events.reduce(reducer, initial);
}
