```typescript
Snapshots serialise aggregate state with a version tag. On load, if the stored version is older than `CURRENT_VERSION`, upgrade functions run in order to migrate the shape, so the aggregate always sees the current schema. The stream itself is not rewritten.

```typescript
export type EscrowCurrentState = Readonly<{
  id: string;
  payer: string;
  payee: string;
  amount: number;
  fee: number;
  currency: string;
}>;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 3 as const;

type V1 = Readonly<{ id: string; payer: string; payee: string; amount: number }>;
type V2 = Readonly<{ id: string; payer: string; payee: string; amount: number; fee: number }>;

function v1Tov2(raw: V1): V2 {
  return { ...raw, fee: 0 };
}

function v2Tov3(raw: V2): EscrowCurrentState {
  return { ...raw, currency: "USD" };
}

export class SnapshotError extends Error {}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<EscrowCurrentState> {
  if (snap.version === CURRENT_VERSION) {
    return snap as Snapshot<EscrowCurrentState>;
  }
  if (snap.version === 1) {
    const v2 = v1Tov2(snap.state as V1);
    const v3 = v2Tov3(v2);
    return { version: CURRENT_VERSION, state: v3 };
  }
  if (snap.version === 2) {
    const v3 = v2Tov3(snap.state as V2);
    return { version: CURRENT_VERSION, state: v3 };
  }
  throw new SnapshotError("UNKNOWN_VERSION");
}
