export type ChargeState =
  | { status: "none" }
  | { status: "authorized"; id: string; amount: number; currency: string }
  | { status: "captured"; id: string; amount: number; currency: string; capturedAt: string };

export type ChargeEvent =
  | { type: "ChargeAuthorized"; id: string; amount: number; currency: string }
  | { type: "ChargeCaptured"; at: string };

export const initialState: ChargeState = { status: "none" };

export function evolve(state: ChargeState, event: ChargeEvent): ChargeState {
  switch (event.type) {
    case "ChargeAuthorized":
      return { status: "authorized", id: event.id, amount: event.amount, currency: event.currency };
    case "ChargeCaptured":
      if (state.status !== "authorized") return state;
      return { status: "captured", id: state.id, amount: state.amount, currency: state.currency, capturedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 2 as const;

type V1 = Readonly<{ status: "authorized" | "captured"; id: string; amount: number; capturedAt?: string }>;

function v1Tov2(raw: V1): ChargeState {
  if (raw.status === "authorized") {
    return { status: "authorized", id: raw.id, amount: raw.amount, currency: "USD" };
  }
  return {
    status: "captured",
    id: raw.id,
    amount: raw.amount,
    currency: "USD",
    capturedAt: raw.capturedAt ?? "",
  };
}

export class SnapshotError extends Error {}

export function loadFromSnapshot(
  snap: Snapshot<unknown> | null,
  newer: ReadonlyArray<ChargeEvent>,
): ChargeState {
  let state: ChargeState;
  if (snap === null) {
    state = initialState;
  } else if (snap.version === CURRENT_VERSION) {
    state = snap.state as ChargeState;
  } else if (snap.version === 1) {
    state = v1Tov2(snap.state as V1);
  } else {
    throw new SnapshotError("UNKNOWN_VERSION");
  }
  return newer.reduce(evolve, state);
}
