import { Effect } from "effect";

export type ChargeEvent =
  | { type: "ChargeAuthorized"; id: string; amount: number }
  | { type: "ChargeCaptured"; at: string };

export type ChargeState =
  | { status: "none" }
  | { status: "authorized"; id: string; amount: number }
  | { status: "captured"; id: string; amount: number };

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ChargeEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: ReadonlyArray<ChargeEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export class ConcurrencyConflict extends Error {}

export function evolve(s: ChargeState, e: ChargeEvent): ChargeState {
  switch (e.type) {
    case "ChargeAuthorized": return { status: "authorized", id: e.id, amount: e.amount };
    case "ChargeCaptured":
      if (s.status !== "authorized") return s;
      return { status: "captured", id: s.id, amount: s.amount };
    default: { const _n: never = e; return s; }
  }
}

const attempt = (
  store: EventStore,
  streamName: string,
  produce: (state: ChargeState) => ReadonlyArray<ChargeEvent>,
) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => store.readStream(streamName));
    const state = events.reduce(evolve, { status: "none" } as ChargeState);
    const produced = produce(state);
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() =>
      store.appendToStream(streamName, produced, { expectedRevision }),
    );
  });

export const handleWithRetry = (
  store: EventStore,
  streamName: string,
  produce: (state: ChargeState) => ReadonlyArray<ChargeEvent>,
) =>
  Effect.gen(function* () {
    try {
      return yield* attempt(store, streamName, produce);
    } catch (err) {
      if (err instanceof ConcurrencyConflict) {
        return yield* attempt(store, streamName, produce);
      }
      throw err;
    }
  });
