export class UnknownEventError extends Error {}

function assertRaw(raw: unknown): asserts raw is RawEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError("NOT_OBJECT");
  if (!("type" in raw)) throw new UnknownEventError("NO_TYPE");
  if (!("version" in raw)) throw new UnknownEventError("NO_VERSION");
}

export function upcast(raw: unknown): CurrentEvent {
  assertRaw(raw);
  switch (raw.type) {
    case "RefundInitiated":
      if (raw.version === 1) {
        return {
          type: "RefundInitiated",
          version: 2,
          id: raw.id,
          amount: raw.amount,
          metadata: { reason: raw.reason },
        };
      }
      return raw;
    case "RefundSettled":
      return raw;
    default: { const _n: never = raw; throw new UnknownEventError("UNKNOWN_TYPE"); }
  }
}

export function upcastAll(raws: ReadonlyArray<unknown>): CurrentEvent[] {
  return raws.map(upcast);
}

export type RefundView = Readonly<{ id: string; amount: number; reason: string | null }>;

export const emptyView: RefundView = { id: "", amount: 0, reason: null };

export function project(view: RefundView, event: CurrentEvent): RefundView {
  switch (event.type) {
    case "RefundInitiated":
      return { id: event.id, amount: event.amount, reason: event.metadata.reason };
    case "RefundSettled":
      return view;
    default: { const _n: never = event; return view; }
  }
}

export function refundViewFrom(raws: ReadonlyArray<unknown>): RefundView {
  return upcastAll(raws).reduce(project, emptyView);
