export type SagaState =
  | { status: "waiting" }
  | { status: "approvedPending"; payoutId: string; amount: number; recipient: string }
  | { status: "disbursed"; payoutId: string; disbursementId: string }
  | { status: "failed"; reason: string };

export type IncomingEvent =
  | { type: "PayoutApproved"; payoutId: string; amount: number; recipient: string }
  | { type: "DisbursementExecuted"; payoutId: string; disbursementId: string }
  | { type: "DisbursementFailed"; payoutId: string; reason: string };

export type OutgoingCommand =
  | { type: "ScheduleDisbursement"; payoutId: string; recipient: string; amount: number }
  | { type: "MarkPayoutDisbursed"; payoutId: string; disbursementId: string }
  | { type: "EscalatePayoutFailure"; payoutId: string; reason: string };

export type SagaStep = Readonly<{ nextState: SagaState; command: OutgoingCommand | null }>;

export const initialState: SagaState = { status: "waiting" };

export function step(state: SagaState, event: IncomingEvent): SagaStep {
  switch (event.type) {
    case "PayoutApproved":
      if (state.status !== "waiting") return { nextState: state, command: null };
      return {
        nextState: {
          status: "approvedPending",
          payoutId: event.payoutId,
          amount: event.amount,
          recipient: event.recipient,
        },
        command: {
          type: "ScheduleDisbursement",
          payoutId: event.payoutId,
          recipient: event.recipient,
          amount: event.amount,
        },
      };
    case "DisbursementExecuted":
      if (state.status !== "approvedPending") return { nextState: state, command: null };
      return {
        nextState: { status: "disbursed", payoutId: state.payoutId, disbursementId: event.disbursementId },
        command: {
          type: "MarkPayoutDisbursed",
          payoutId: state.payoutId,
          disbursementId: event.disbursementId,
        },
      };
    case "DisbursementFailed":
      if (state.status !== "approvedPending") return { nextState: state, command: null };
      return {
        nextState: { status: "failed", reason: event.reason },
        command: { type: "EscalatePayoutFailure", payoutId: state.payoutId, reason: event.reason },
      };
    default: { const _n: never = event; return { nextState: state, command: null }; }
  }
}

export function evolve(state: SagaState, event: IncomingEvent): SagaState {
  return step(state, event).nextState;
}

export function aggregate(events: ReadonlyArray<IncomingEvent>): SagaState {
  return events.reduce(evolve, initialState);
}
