    case "ChargeAuthorized":
      return {
        schema: "charge.authorized.v1",
        payload: { chargeId: event.id, amount: event.amount, authorizedAt: event.authorizedAt },
      };
    case "ChargeCaptured":
      return {
        schema: "charge.captured.v1",
        payload: { chargeId: event.id, capturedAt: event.at },
      };
    case "ChargeVoided":
    case "ChargeMetadataUpdated":
      // internal-only; do not publish
      return null;
    default: { const _n: never = event; return null; }
  }
}

export type OutboxView = Readonly<{ pending: ReadonlyArray<IntegrationEvent> }>;

export const emptyOutbox: OutboxView = { pending: [] };

export function project(view: OutboxView, event: DomainEvent): OutboxView {
  const translated = translate(event);
  if (translated === null) return view;
  return { pending: [...view.pending, translated] };
}
