```typescript
export type ReconciliationState =
  | { status: "none" }
  | { status: "running"; id: string; matched: number; unmatched: number }
  | { status: "completed"; id: string; matched: number; unmatched: number };

export type ReconciliationCommand =
  | { type: "start"; id: string }
  | { type: "recordMatch" }
  | { type: "recordMismatch" }
  | { type: "complete" };

export type ReconciliationEvent =
  | { type: "ReconciliationStarted"; id: string }
  | { type: "EntryMatched" }
  | { type: "EntryUnmatched" }
  | { type: "ReconciliationCompleted" };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const reconciliationDecider: Decider<ReconciliationCommand, ReconciliationEvent, ReconciliationState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "start":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ReconciliationStarted", id: command.id }];
      case "recordMatch":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "EntryMatched" }];
      case "recordMismatch":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "EntryUnmatched" }];
      case "complete":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "ReconciliationCompleted" }];
      default: { const _n: never = command; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ReconciliationStarted":
        return { status: "running", id: event.id, matched: 0, unmatched: 0 };
      case "EntryMatched":
        if (state.status !== "running") return state;
        return { ...state, matched: state.matched + 1 };
      case "EntryUnmatched":
        if (state.status !== "running") return state;
        return { ...state, unmatched: state.unmatched + 1 };
      case "ReconciliationCompleted":
        if (state.status !== "running") return state;
        return { status: "completed", id: state.id, matched: state.matched, unmatched: state.unmatched };
      default: { const _n: never = event; return state; }
    }
  },
};
```
